1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type QuoteStep = {
6	  op: "quote";
7	  items: unknown[];
8	};
9	
10	export type Step = QuoteStep;
11	
12	export type Scenario = {
13	  customer: Customer;
14	  steps: Step[];
15	};
16	
17	export type QuoteResult = {
18	  premium: number;
19	};
20	
21	export type Result = QuoteResult;
22	
23	const PROCESSING_FEE = 5;
24	
25	export const processScenario = (scenario: Scenario): { results: Result[] } => {
26	  if (scenario.steps[0].items.length === 0) {
27	    return { results: [{ premium: PROCESSING_FEE }] };
28	  }
29	  return { results: [{ premium: 115 }] };
30	};
